'use client'
import { useState } from 'react'
import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { motion, AnimatePresence } from 'framer-motion'
import { 
  HomeIcon,
  ShoppingCartIcon,
  CubeIcon,
  CreditCardIcon,
  Bars3Icon,
  PlusCircleIcon,
  ChartBarIcon
} from '@heroicons/react/24/outline'
import { cn } from '@/lib/utils'

const nav = [
  { href: '/', label: 'Dashboard', icon: HomeIcon },
  { href: '/pos', label: 'POS', icon: ShoppingCartIcon },
  { href: '/products', label: 'Products', icon: PlusCircleIcon },
  { href: '/inventory', label: 'Inventory', icon: CubeIcon },
  { href: '/sales', label: 'Sales', icon: ChartBarIcon },
  { href: '/checkout', label: 'Transactions', icon: CreditCardIcon }
]

export function Sidebar() {
  const [isOpen, setIsOpen] = useState(true)
  const pathname = usePathname()
  
  return (
    <motion.div
      className="h-full bg-white border-r border-gray-200"
      initial={false}
      animate={{ width: isOpen ? 256 : 80 }}
      transition={{ duration: 0.3, ease: "easeInOut" }}
    >
      <div className="p-6 h-full flex flex-col">
        {/* Header with Logo/Toggle */}
        <div className="flex items-center justify-between mb-8">
          <motion.button
            onClick={() => setIsOpen(!isOpen)}
            className="p-3 hover:bg-gray-100 rounded-lg transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <Bars3Icon className="size-6 text-gray-700" />
          </motion.button>
          
          <AnimatePresence>
            {isOpen && (
              <motion.div
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
                className="font-semibold text-gray-900 text-lg"
              >
                POS System
              </motion.div>
            )}
          </AnimatePresence>
        </div>
        
        {/* Navigation Items */}
        <nav className="flex-1 space-y-2">
          {nav.map(({ href, label, icon: Icon }) => {
            const isActive = pathname === href
            
            return (
              <Link key={href} href={href}>
                <motion.div
                  className={cn(
                    'flex items-center gap-3 p-4 rounded-lg cursor-pointer transition-colors',
                    isActive 
                      ? 'bg-blue-50 text-blue-600' 
                      : 'text-gray-600 hover:bg-gray-50',
                    isOpen ? 'justify-start' : 'justify-center'
                  )}
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                >
                  <Icon className="size-5 shrink-0" />
                  
                  <AnimatePresence>
                    {isOpen && (
                      <motion.span
                        initial={{ opacity: 0, width: 0 }}
                        animate={{ opacity: 1, width: 'auto' }}
                        exit={{ opacity: 0, width: 0 }}
                        transition={{ duration: 0.2, delay: 0.1 }}
                        className="font-medium whitespace-nowrap"
                      >
                        {label}
                      </motion.span>
                    )}
                  </AnimatePresence>
                </motion.div>
              </Link>
            )
          })}
        </nav>
      </div>
    </motion.div>
  )
}